def analyse_sbom(sbom_text: str) -> str:
    try:
        data = json.loads(sbom_text)
    except Exception as e:
        return f"Validity: Invalid JSON\nError: {str(e)}"

    if data.get("bomFormat") != "CycloneDX":
        return "Format: Not CycloneDX\nValidity: Failed"

    findings = []
    findings.append("Format: CycloneDX")
    findings.append(f"Spec Version: {data.get('specVersion', 'Missing')}")

    components = data.get("components", [])
    findings.append(f"Component Count: {len(components)}")

    issues = []

    for c in components:
        name = c.get("name", "unknown")
        version = c.get("version", "unknown")
        comp_issues = []

        if "purl" not in c:
            comp_issues.append("missing purl")
        if "licenses" not in c:
            comp_issues.append("missing license")
        if "hashes" not in c:
            comp_issues.append("missing hash")

        if comp_issues:
            issues.append(f"{name}@{version}: " + ", ".join(comp_issues))

    if issues:
        findings.append("Security Issues:")
        findings.extend(issues)
    else:
        findings.append("Security Issues: None detected")

    return "\n".join(findings)
